__NUXT_JSONP__("/HomeMDMA", (function(a,b,c,d,e,f,g,h,i,j,k,l,m,n,o,p,q,r,s,t,u,v,w,x,y,z,A,B,C,D,E,F,G,H,I,J,K,L,M,N,O,P,Q){return {data:[{articles:[{slug:"FrancescoP-Accade-1",tema:e,titolo:"Accade",autore:j,parole:"a volte, fato, sesso selvaggio, ribelli, gioia, sulla tavola, labirinto, domani, crocevia",data:s,tags:e,img:p,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Ehh a volte io ho fato sesso selvaggio anche senza pagare. Lo so io da me che vivo ribelli.\nMa con gioia, sai?\nEh si anche sulla tavola! E mica quella della casa, parlo della tavola del surf per non dirti di quella da stiro!\nE' mica facile sai? Te voglio proprio vedere in un labirinto di gambe, braccia e il resto non te lo dico\nperche' sono timido.\nGia'  domani c'ho un incontro con la contorsionista. Gia'.\nE' da vedere sai?\nE' come sentirsi come cristo sul crocevia!"}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Accade-1",extension:h,createdAt:x,updatedAt:i},{slug:"Elisa-Assuefazione-1",tema:k,titolo:k,autore:l,parole:y,data:m,img:z,tags:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Con aria distratta osservò la gabbia davanti a me, non ha sbarre ma una sottile lastra\ndi vetro trasparente che ti permette di osservare il robot, dalle sembianze femminili che,\nnell'intimità del privet dell'ennesimo locale che ho deciso di frequentare, per distrarmi\nda un mondo oramai irriconoscibile, balla sensuale su quel cubo magico o almeno\ncosì mi appare, grazie ai suoi giochi di luci e colori che risultano accecanti agli occhi umani."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Con la musica che rimbomba nella stanza, dando il ritmo alla ballerina, lascio che la mia\nmente vaghi nella fantasia di ricordi passati e momenti appartenenti alla vita di prima,\nquando il mondo non era stato rimpiazzato dalla scienza, quando ancora quella meteora\naliena non si era schiantata sulla terra trasformando  tutto e tutti,  facendo sì che il\npianeta che conoscevamo andasse incontro a una rinascita diventando un mondo di\nrazze aliene da combattere, tecnologia ultra sofisticata tanto da permettere ai robot\ndi prendere il posto degli umani."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Non esiste più niente della nostra cultura, l'amore e la bellezza che il corpo di una\nspogliarellista poteva regalare è stato sostituito dalla freddezza e dalla durezza dell'acciaio\nmodellato a finché la nostra mente venisse ingannata."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Chiudo gli occhi, appoggiandomi allo schienale della sedia, rivestita di cuoio rosso su cui\nsono seduto, non mi interessa più seguire quello spettacolo per cui ho pagato, ora preferisco\ndi gran lunga perdermi in quel mondo ovattato di cui mi è rimasto un misero e sfumato\nricordo che aleggia nei miei pensieri come una nuvola bianca che può essere spazzato\nvia con un semplice soffio di vento."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Mi perdo così nelle memorie di quando ero solo un professore della Yale,\nmi perdo fino a che non sento la porta aprirsi e un soldato fare il mio nome"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"S ; sergente Karter, la zona B é sotto attacco, é richiesto il suo aiuto nell'immediato."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Sono quelle parole che mi fanno aprire gli occhi, lasciando affievolire il magnetismo che\nmi spinge in quei ricordi di una vita che so non potrà più tornare."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Ed é così che con malinconia, afferrò il mio fucile a energia cinetica Stark\ne abbandono la stanza, dove, la ballerina robotica, che nemmeno si é accorta della\nmia assenza, continua a ballare, nello stesso modo automatico in cui io mi dirigo a passi\nsvelti alla missionea che mi é stata appena assegnata."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FElisa-Assuefazione-1",extension:h,createdAt:v,updatedAt:"2021-07-05T16:27:18.064Z"},{slug:"Elisa-Assuefazione-2",tema:k,titolo:k,autore:l,parole:A,data:m,img:z,tags:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Eccomi ora a pagare il prezzo per quelle bugie."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Legato con del nastro adesivo che mi tappa la bocca\ne la corda che mi lega i polsi penso a quanto io sia stato stupido."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Sapevo il rischio di mentire, eppure l'ho voluto fare, ho voluto mentire al cliente\npresso il quale il mio capo mi aveva inviato, pensavo di fregarlo e invece alla fine\né stato lui a farlo e ora eccomi qua a fissare la spia davanti a me in gonna\ne tacchi a spillo, che, in piedi davanti a un banco sceglie il prossimo strumento\ncon il quale punirmi per i miei errori."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Quanto stupido sono stato? Ho pensato, come un topo che insegue una\nscia di formaggio, di fregare quelli più forti di me, ho pensato di poter diventare\nil braccio destro del mio capo, ma poi proprio come un topo che cade in trappola\nio sono caduto prigioniero del mio inconsistente desiderio di riuscire finalmente\na farmi un nome tra i potenti."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Chiudo gli occhi, cercando un evasione dal dolore, andando a riesumare nella\nmia testa il ricordo di vecchi e squallidi strip club e la figura di qualche cubista\nche rende ancora più sporca la mia coscienza."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Quando riapro gli occhi, vedo una pistola puntata contro quella donna e il mio\ncollega venire verso di me e slegarmi."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Sollievo é ciò che sento ora, lo stesso sollievo che ti fa provare un amico che\nti aiuta nel disamore di una qualche relazione andata male e che alla fine\nti fa sentire libero."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"”La vita ha scelto di darmi un'altra possibilità” penso mentre vedo\nil posto in cui ero tenuto prigioniere cadere nella distruzione, dopo che Harry,\nla persona che mi ha salvato, ha deciso di farlo saltare in aria."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Un'altra possibilità...penso, mentre salgo nella macchina che mi porter�\ndefinitamente in salvo...una possibilità che andrò a cogliere cercando un\nnuovo lavoro, abbandonando la strada del crimine e magari chi lo sa,\nandando a crearmi una famiglia."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FElisa-Assuefazione-2",extension:h,createdAt:v,updatedAt:"2021-07-05T16:29:00.925Z"},{slug:"FrancescoP-Assuefazione-1",tema:k,titolo:k,autore:j,parole:"affanno, buio, dolore, sudore, griglia, salita, inutilita', gioco, insensibilita', rabbia, vita",data:"20 gennaio 2021",tags:e,img:n,video:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"1\nQuando il faraone egizio Tolomeo III tra il 246 ed il 222 a.C. fondo' la citta' di Assuan non avrebbe mai immaginato di dover\ncontrastare una fazione di beduini contrari al suo progetto. Erano questi la assuanfazione ...\nI contrasti furono violenti e nonostante la enorme disparita' delle forza, Tolomeo poteva contare su un esercito\ndi 600000 uomini mentre la assuanfazione disponeva al massimo di 130 uomini abili al combattimento, la rivolta\nduro' per molti anni prima di essere sedata."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"3\nSuccede quando hai una dipendenza. C'e' la fazione di assuan (l'assuanfazione) che ti crea AFFANNO, la fazione\nche contrasta con il resto dell'essere che vorrebbe creare un nuovo paesaggio, magari piu' salubre, e che\nnonostante la disparita' di forze riesce a proseguire la sua attivita' di disturbo per svariati anni.\nFino ad essere sedata, con la vita o con la morte."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"2\nE' dal BUIO profondo di questa grotta che sto scrivendo quelle che potrebbero essere le mie ultime parole.\nIn questi brevi attimi di lucidita', sempre piu' rari e brevi, nei quali il DOLORE costantemente presente si attenua un poco ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"1\nE queste furono le ultime parole che decifrai nel rotolo di Salbus, dal nome della grotta in cui fu ritovato.\nIgnoto e' l'autore ma sappiamo che all'epoca nella zona viveva una tribu' seminomade che poco dopo venne\ncompletamente annientata dall'esercito di Cesarione. Supponiamo quindi che l'autore fosse uno degli ultimi sopravvissuti\ndella tribu' nascostosi, forse gravemente ferito, in quella grotta."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"3\nLeggere questi libri storici fa girare la testa. Ci sono momenti in cui il SUDORE mi cola sugli occhi e quasi mi impedisce\ndi leggere. Mi ci immedesimo. Immagino di vivere in quel contesto storico e cerco di capirne la vita.\nMa per fortuna sto vivendo adesso e posso permettermi di fermare la storia per occuparmi della mia cena. Devo andare a girare\nle salsiccie che ho sulla GRIGLIA. Salsiccie e pure', devo dire un'ottima cena. Accompagnata da un bicchiere di buon Chianti."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"1\nLa SALITA che porta alla grotta di Salbus e' nevvero irta ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"2\n... la lotta si e' rivelata come l'ultimo atto che potessimo compiere e la sua INUTILITA' non inficia il nostro sacrificio ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"1\nIn questo frammento del rotolo possiamo arguire che l'ignoto estensore cercasse di lasciarci una sorta di testimonianza\ndella rivolta in atto. Un GIOCO non nuovo. La parte vinta, in questo caso diremmo completamente annientata, desidera\nche rimanga la conoscienza di quanto avvenuto, desidera che la memoria conservi un ricordo."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"3\nE poi ci ritrovi questi mezzi sermoni ... La parte vinta ... i vincitori ...\nAvverto un'INSENSIBILTA' nei confronti di una della parti, come se fosse necessario prendere posizione per una di queste.\nA volte mi immedesimo in quella parte di persone che non hanno deciso, che non hanno scelto, che rimangono a meta'.\nIn disparte ma coinvolti. Forse immuni dalla RABBIA che si trasforma in lotta prima e in violenza poi."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"1\nSecondo alcuni studiosi basandosi sulle recentissime scoperte testimoniali del sito di Babur, a pochissima distanza dalla grotta\ndi Salbus, l'estensore del papiro potrebbe identificarsi in Pelonius futuro re di Babur. Si ipotizza che Pelonius rifugiatosi nella\ngrotta ferito ne sia poi uscito guarito e abbia ripreso la lotta riuscendo infine a riconquistare il territorio della sua tribu'.\nSe questo fosse vero dovremmo riscrivere la storia fin qui conosciuta e riconoscere quindi che le nostre conoscenze sono\nerrate."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"3\nLo sapevo che c'era la fregatura ... La storia ha ripreso VITA."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Assuefazione-1",extension:h,createdAt:B,updatedAt:i},{slug:"FrancescoP-Assuefazione-2",tema:k,titolo:k,autore:j,parole:"gabbia, robot, intimita', cubo magico, fantasia, rinascita, amore, acciaio, ovattato, nuvola, magnetismo",data:"10 febbraio 2021",tags:e,img:n,video:"https:\u002F\u002Fwww.youtube.com\u002Fembed\u002FCTsVVfCPPCg",toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"C'e' una fitta rete di sottili fili metallici che mi avvolge. La chiamano GABBIA. Ma io non me ne accorgo neanche piu'.\nE' da troppo tempo che la indosso.\nDicono \"basta ti soffochera', andra' a finire che ti uccidera'\" ma a me non interessa.\nMorire protetto e' sempre meglio che morire di dolore o di paura.\nQuelli che parlano e mi giudicano sembrano dei ROBOT programmati per vedere e fare solo cio' che e' stato previsto.\nSono, secondo me, inumani.\nEppure avranno anche loro delle falle. Nella loro INTIMITA' avranno dubbi e pensieri oltre il programmato.\nMa probabilmente non l'accettano, rifutando cosi' se stessi.\nE lo faccio anch'io proteggendomi o nascondendomi con la mia fitta rete di sottili fili metallici.\nMa io ne sono consapevole ... o forse no.\nForse aspetto solo un CUBO MAGICO che mi risolva, che risolva l'enigma di me stesso.\nChi sono io davvero?\nQuanto mi fa paura di me stesso e quanto sono cio' che non sono e quanto c'e' di bello, se c'e', in me?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Infine un giorno il vento della FANTASIA mi travolse con un lieve tepore.\nCominciai a sognare. Sognai di esseri che sono cio' che sono e che non si preoccupano di cio' che sono,\ne che non vedono altro che cio' che gli altri sono. Con chiarezza, lucidita' e semplicita'.\nForse un incubo!\nMa fu' a partire da quel sogno, poi ne feci moltri altri, che in me vi fu' una sorta di RINASCITA.\nCominciai a vedere ciecamente me stesso. Cominciai a sentire la magnifica sordita'.\nCominciai a tastare il nulla.\nFu' la morte della vita e fu' l'inizio dell'AMORE.\nUna spranga d'ACCIAIO mi sbatte' con tale violenza sulla testa che morii a me stesso e fui anima.\nE fluttuando nel brodo primordiale avevo caldo, un tale splendido caldo che fuse la mia\narmatura immaginaria di sottili fili metallici.\nFinalmente ero. Finalmente sono. Finalmente saro'."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"E nell'OVATTATO infinito multiverso ho trovato la NUVOLA che ero, che sono e che saro'.\nEd e' cosi' che voi mi vedrete ... nuvola. E nei vostri rigidi pensieri qualcosa vi fara' dire\n\"Oh che bella nuvola\", ma solo perche' cosi' siete stati programmati.\nE nemmeno quella forma di MAGNETISMO che vi portera' ogni volta ad alzare lo sguardo al cielo\nalla ricerca di quella bella nuvola vi fara' capire mai che non c'e nulla da guardare."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Assuefazione-2",extension:h,createdAt:B,updatedAt:i},{slug:"FrancescoP-Assuefazione-3",tema:k,titolo:k,autore:j,parole:"noia, dipendenza, muro, niente, alibi, inizio, esperienza, abuso, insoddisfazione, voglia, distanza",data:"3 febbraio 2021",tags:e,img:n,video:"https:\u002F\u002Fwww.youtube.com\u002Fembed\u002F_BBnLXbEZWw",toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Ciao ragazzi, oggi vi parlero' di uno stato dell'essere ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"(... che NOIA ...)"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"... il quale, per inciso, porta a quella che viene definita DIPENDENZA, ovvero ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"... ed e' certo quanto accadde nel 1989 alla caduta del MURO di Berlino, che porto' ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"NIENTE"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"... e certamente questi sono i cosiddetti ALIBI ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"... ma poiche' tutto ha un INIZIO, anche se il concetto e' tuttora da validare ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"... ed e' frutto della nostra ESPERIENZA maturata in anni di ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"... e fu' solo nel 1245 che l'ABUSO di potere da parte ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"... dovuta perlopiu' all'INSODDISFAZIONE che si stava allora ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"... pur con l'effettiva VOGLIA di risolvere il problema alla ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"... ma tutto cio' e' bene guardarlo da una certa DISTANZA."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Assuefazione-3",extension:h,createdAt:C,updatedAt:i},{slug:"FrancescoP-Assuefazione-4",tema:k,titolo:k,autore:j,parole:"bugie, nastro, corda, tacchi a spillo, inconsistente, evasione, cubista, coscienza, sollievo, disamore, distruzione",data:"27 gennaio 2021",tags:e,img:n,video:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Quante BUGIE ...\nQuante bugie raccontiamo agli altri e quante raccontiamo a noi stessi ...\nQuante?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"E per cosa poi?\nPer non volere fare vedere chi siamo davvero? Per non volerci vedere?\nQuante bugie ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Un lunghissimo NASTRO di bugie che diventano la CORDA a cui impicchiamo noi stessi."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"\"Le bugie hanno le gambe corte ...\""}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Si ma hanno anche i TACCHI A SPILLO!\nNon solo non vai lontano ma ci vai pure barcollando!"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Si direbbe la creazione di una esistenza INCONSISTENTE.\nRealta' parallela e fittizia che costruiamo nel pensiero e adottiamo nella vita\nsenza neanche riuscire a viverla perche' non e' neppure quella che vorremmo!\nCreiamo realta' che nemmeno ci piacciono!\nE poi, inconsapevoli, organizziamo la grande EVASIONE dalla realta' effimera che ci siamo costruiti addosso e intorno."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"E come una CUBISTA ci scateniamo, sensualmente, piu' o meno abilmente, ad attirare gli altri nella nostra realta'."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Vivere una vita che non e' la nostra, alla quale vogliamo credere perche' pensiamo che sia la vita che altri desiderano\ne che eppure non ci piace. Ma quanto siamo contorti?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Ma quanta sofferenza alla nostra COSCIENZA ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Il SOLLIEVO? Ma certo! Droga, alcool, gioco, violenza, sesso, rumore e perche' no? un poco di rock'n'roll. Ma poco,\npotrebbe essere troppo sano e certo non ci fa bene."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Con quanto DISAMORE ci amiamo? Con quanto disamore amiamo noi stessi e gli altri?\nCon quanto disamore bombardiamo l'universo?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"L'immancabile DISTRUZIONE puo' essere evitata solo distruggendo pezzo a pezzo la nostra pseudo vita.\nE se mai ci riusciste forse allora, solo allora, vedrete la vita.\nQuella vera? Non lo so, ma quantomeno quella vostra.\nE poi ricordatevi: non portate i tacchi a spillo, tanto si barcolla lo stesso!"}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Assuefazione-4",extension:h,createdAt:C,updatedAt:i},{slug:"Elisa-Boomerang-1",tema:e,titolo:q,autore:l,parole:"serie 1",data:m,img:t,tags:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Fu così che il giudice iniziò il processo a quel viandante."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Tre colpi di martelletto sul bancone di legno lucido e via, quell'uomo sconosciuto ma decisamente buffo sarebbe stato sottoposto a domande che avrebbero portato a un verdetto che ne decretava la morte o la vita dietro le sbarre."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Non avevo ben capito le dinamiche di ciò che era successo, non avevo capito come quel viandante era finito sull'autostrada, forse era sbronzo o forse, visto anche gli abiti che indossava, poteva essere un uomo di Neandertal uscito dalla caverna e, spaesato dal mondo odierno, aveva imboccato la sopraelevata finendo tra le macchine che, se non avessero frenato, avrebbbero fatto fare a quel pover'uomo l stessa misera fine di una pietra che finisce sotto lo schiacciasassi."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"\"Non lo so com'è c'è finito il mio sperma sulla vittima\""}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Sperma? Oh signore mio! Ho confuso un processo per un altro, quello di cui stavo parlando è il processo avvenuto tre mesi fa a New York, questo invece è il caso dell'omicidio Michelle e l'uomo alla sbarra non è di certo Hanry, ma decisamente un uomo più malvagio e sicuramente colpevole che merita di marcire in una cella di cui le guardie hanno perso la chiave…no, forse non avrei dovuto fermarmi a bere con quel Portoricano ma...come non farlo? Era dannatamente carino… ."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"No, ok, devo smetterla, smetterla di pensare all'incontro di stare e concentrarmi sul caso, anche perché tra poco il giudice chiamerà me a interrogare il sospettato e se voglio fare ritorno a casa con ancora la mia licenza da avvocato devo assolutamente spedire questo spregiudicato in gattabuia con l'ergastolo o rischio di finirci io in una caverna."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FElisa-Boomerang-1",extension:h,createdAt:v,updatedAt:i},{slug:"Elisa-Boomerang-2",tema:e,titolo:q,autore:l,parole:"serie 2",data:m,img:t,tags:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Ho Intrapreso un lungo viaggio sai? Ho attraversato aridi deserti, fitti boschi e lande piene di strane creature per riuscire a portarti questo specchio."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Che ha di speciale?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"È uno specchio il cui vetro è formato dalla polvere delle stelle e il manico è invece un mix di schegge lunari e oro zecchino Ed è tuo, Andria, è il mio regalo per te"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"E perché tu mi faresti un regalo?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Perché voglio farti vedere quanto sei bella"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Una risata si levò dalle labbra di Andria mentre si specchiava in quel piccolo magico oggetto che aveva tra le mani e che sembrava davvero risaltare la sua bellezza in un modo a dir quasi angelico."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Sorrise, posando poi i suoi occhi dorati su di lui"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Si beh, anche io ti ho fatto un regalo"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"E che regalo?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Questo"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:b,tag:u,props:{},children:[{type:a,value:"Andria estrasse un piccolo ramoscello di mimosa il cui colore però era rosso fuoco"}]}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Un fiore?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Non è un semplice fiore, esso è intriso dello spirito di tyr, dio della giustizia e della guerra, se in battaglia l'avrai sempre con te, legato alla tua armatura ogni vittoria sarà tua"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"\"Ok zio ma ora basta io ti avevo chiesto come nasce un proverbio, non di raccontarmi una storia\""}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Ma è proprio per la tua richiesta che devo narrarti una storia"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Perché?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Perché è proprio dalle storie che nascono i proverbi."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FElisa-Boomerang-2",extension:h,createdAt:D,updatedAt:i},{slug:"Elisa-Boomerang-3",tema:e,titolo:q,autore:l,parole:y,data:m,img:t,tags:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Leonora aveva intrapreso una strada pericolosa, l'alchimia difatti è figlia della scienza e della magia, ma se si usa troppa magia si cade nella stregoneria e quindi nell'eresia."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"A Leonora era successo proprio questo, cercando la fama in qualità di alchimista finì per essere vista come una strega, una traditrice che il tiranno Azazel, del regno di Volk decise di punire."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"\"È una strega! E per questo dovete lasciare che il suo sangue demoniaco scorra per tutta la piazza e sia d'esempio ai cittadini che vogliono usare la magia come arma contro il loro signore\""}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Queste furono le parole che diedero il via all'esecuzione di Leonora la quale, prima di finire alla forca, decise di bere un elisir che lei stessa aveva creato, mischiando Azoto, ammonio, oro e alcune erbe dalle proprietà curative sconosciute."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Lo bevve davanti a tutti, gettando poi la boccetta di vetro in terra e solo allora fu pronta a morire per mano del boia."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Quando però l'ascia calò su di lei, a terra si riversò, al posto del suo sangue un liquido giallo, luccicante che ben presto attirò i bambini che, insieme ai loro genitori, erano venuti ad assistere alla morte di Leonora."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Golosi i fanciulli iniziarono a mangiare le caramelle e inutile dire le grida che si sollevarono dalle bocche di tutti quando si accorsero che la pelle dei bambini stava diventando blu, un blu...un blu scuro, mai visto."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"\"Allora, James, ancora dietro a scrivere quel tuo stupido romanzo?\""}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:b,tag:u,props:{},children:[{type:a,value:"James alzò lo sguardo dal computer, posizionandolo sull'amico appena entrato in stanza"}]}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Si, sai com'è ho bisogno di scrivere, di sfogare questo mio pensiero vulcanico"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Quindi se ti invito per una birra rifiuterai?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:b,tag:u,props:{},children:[{type:a,value:"James scosse la testa ridendo e andando a chiudere il proprio portatile, che lasciò sul letto prima di alzarsi e uscire dalla camera"}]}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Come potrei mai rifiutare una birra con mio fratello?."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FElisa-Boomerang-3",extension:h,createdAt:D,updatedAt:i},{slug:"Elisa-Boomerang-4",tema:e,titolo:q,autore:l,parole:A,data:m,img:t,tags:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Nina guardava emozionata tutte quelle colorate acrobazie, guardava Il presentatore annunciare tutti gli artisti, uno a uno e li guardava esibirsi in numeri a dir poco pazzeschi che potevano essere considerati quasi da paese delle meraviglie."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Nina osservava ogni artista esibirsi nel proprio spettacolo, osservava il nano travestito da Napoleone, cavalcare per tutto il recinto di sabbia quell'elefante enorme, sul cui manto grigio, qualcuno aveva disegnato fiori e spirali colorate, osservava Claude dominare sul fuoco, facendo volteggiare in aria fiaccole fiammeggianti ed esibirsi in numeri da mangiafuoco, lasciando che il caldo di quelle fiamme venisse percepito anche dalle platee su cui il pubblico era seduto, osservando attento le meraviglie che avvenivano sotto il tendone a righe bianche e rosse che odorava di zucchero filato, mele caramellate e popcorn al burro."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Certo…a otto anni Nina non avrebbe mai immaginato che quelle acrobazie divenissero il suo mestiere, che il suo sogno si esaudisse, che riuscisse a diventare una circense e unirsi a quel circo di artisti francesi a cui i suoi genitori erano soliti portarla quando era solo una bambina, eppure fu così."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Nina riuscì a unirsi al circo e ora, osservava quello stesso spettacolo da dietro le quinte, aspettando che il presentatore la annunciasse."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Non ci volle molto perché ciò avvenisse e quando la musica terminò e le zebre ballerine lasciarono il recinto di sabbia, Nina afferrò il suo cerchio azzurro e argentato vedendo poi il presentatore arrivare al centro del tendone e sentendola annunciarla poco dopo con Parole che Nina aveva ormai imparato a memoria."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"\"Pubblico, signori, signore e miei cari bambini, avete visto di tutto, avete visto zebre ballare, leoni ruggire sotto il comando di un solo uomo, avete visto dominare il fuoco e l'acqua, ma ora preparatevi a Nina! Una fanciulla arrivata fino a noi dalla giosa e colorata Città di Napoli, una ragazza di soli vent'anni che questa sera si esibirà per voi in un allegra e caotica TARANTELLA!\""}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"E fu qui che la voce del presentatore venne sostituita dalla musica che annunciò l'ingresso di Nina."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"La giovane italiana afferrò così il suo cerchio e corse fuori dalle quinte, corse al centro del circo di sabbia, sentendo gli applausi di un pubblico che, lei sapeva, per certo, avrebbe incantato."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FElisa-Boomerang-4",extension:h,createdAt:E,updatedAt:i},{slug:"FrancescoP-Boomerang-1",tema:q,titolo:q,autore:j,parole:"viaggio, specchio, quanto sei bella, risata, mimosa, rossa, spirito, proverbio",data:"31 marzo 2021",tags:e,img:n,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Un VIAGGIO attraverso l'anima profonda ...\nE lo SPECCHIO che riflette al cieco dice: \"QUANTO SEI BELLA\".\nE il cieco che non vede ma ci sente benissimo esplode in una profonda e serena RISATA.\n\"E io che pensavo di essere un bell'uomo!\" dice a mezza voce.\nE lo specchio che non vede ma anche lui ci sente benissimo risponde un poco offeso:\n\"parlavo della tua anima, stupido, non del tuo aspetto!\".\nIl cieco , sempre ridendo, con uno sguardo perso ma fisso verso lo specchio sussurra:\n\"Stavo scherzando, vecchio amico, dai non offenderti, stavo solo scherzando un po'\"."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Il vaso sulla tavola contiene un splendida MIMOSA e per un istante, solo per un istante,\ni raggi del sole lo colpiscono mandando riflessi multicolori sulla parete bianca.\nImmagini che ne' il cieco ne' lo specchio possono vedere e che eppure entrambi\npercepiscono come calda e ROSSA emanazione del profondo."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"\"Scherzavo un po', dai non offenderti, vecchio amico, stavo scherzando\".\nE lo specchio cieco con lo sguardo fisso e perso ma verso il cieco sussurra:\n\"Non e' il tuo aspetto, stupido e' la tua anima di cui parlo!\".\nUn poco offeso il cieco che non vede ma sente risponde a mezza voce:\n\"E io che pensavo di essere un bell'oggetto!\"\nLa serena e profonda risata dello specchio esplode nell'aria perche' lui non vede\nma ci sente benissimo.\nIl cieco riflettendosi nello specchio dice: \"quanto sei bella\".\nUn profondo viaggio attraverso l'anima."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Ora se proprio ci devo mettere questo benedetta parola PROVERBIO, ecco che ve la\nmetto:\n\"Dice il proverbio A caval donato non si guarda in bocca!\"\nCome sei bella anima mia."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Boomerang-1",extension:h,createdAt:F,updatedAt:i},{slug:"Francesca-Carmen",tema:e,titolo:"Carmen",autore:G,parole:e,data:r,tags:e,img:p,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"La chiamavano da sempre \"la pazza\"! Fina da piccola era solita canticchiare,\nda sola e senza curarsi di niente e di nessuno, la medesima melodia fino allo\nsfinimento! E se pazza non lo diventava sul serio, sicuramente lo diventavano\ntutti gli altri! Con il suo cagnolino perosapeva essere pieno d'amore, l'unica\ncreatura che non la giudicava e che la stava ad ascoltare per ore nonostante\nla usa indole fosse esuberante per non dire turbolenta.\nLa sua voce a volte sapeva assumere un'aria malinconica ... quasi struggente,\nsenza motivo apparente, almeno per chi riteneva di conoscerla a sufficienza.\nIn quie momenti cio' che poteva farla tornare a sorridere era solo il profumo di pane,\nappena sfornato dalla nonna, che si spargeva in tutta la casa come una dolce promessa\ndi pace e di godimento.\nLa sua comicita' stava nell'essere imprevedibile e nel dissacrare anche i momenti piu' consueti ...\ncome ad esempio cantare a tavola di fronte al suo piatto preferito, diventare\nguerriera davanti ad un lenzuolo steso al sole (come un toro davanti a un drappo rosso),\ndistruggere ogni calendario insieme al suo fidato pepe per eliminare le ricorrenza\npiu' noiose.\nQuando qualcuno le chiedeva ragione di tutto cio', lo guardava negli occhi\nsognante ... come se si trovasse altrove in un altro sistema solare\ncircondata solo da tanti animali amici!"}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancesca-Carmen",extension:h,createdAt:x,updatedAt:i},{slug:"FrancescoP-Cuore_selvaggio-1",tema:e,titolo:"Cuore selvaggio",autore:j,parole:"ribelle, dimenticato, tributo, rosso fuoco, arde, temperatura, perdono, montagna",data:s,tags:e,img:n,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Sono un ribelle dimenticato. Ho pagato il mio tributo alla storia, e nessuno si ricorda piu' di me.\nQuel rosso fuoco che ardeva nelle mie vene ora e' legna che arde per scaldare la temperatura che, qui in ospizio,\ne' sempre troppo bassa. O almeno io lo credo. Non mi sono mai posto il problema del perdono.\nE' stato quel che e' stato. Ognuno vive con cio' che e'.\nSi vive come in montagna. Con poco. Ma anche lì, allora, avevo freddo."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Cuore_selvaggio-1",extension:h,createdAt:F,updatedAt:i},{slug:"AnnaG-Diego",tema:e,titolo:H,autore:"Anna G",parole:e,data:r,tags:e,img:p,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Diego, vestito con la sua maglia preferita rosso blu, stava giocando\na pallone con i suoi amici, con un azione quasi acrobatica aveva centrato\nin pieno l angolo della porta ,una grande ovazione parti dagli spalti del\npiccolo campo da calcio, i tifosi avversari iniziarono a urlare frasi offensive\na Diego, una di queste colp� in modo particolare il giovane calciatore:\nsei grasso come un Buddha che carburante usi!\nL'animo cristallino di Diego subito si offese e come un possente ariete\nsegu� il suo istinto e si scagli� contro chi urlava il coro di ingiurie .\nTornando a casa, ripensava all' accaduto e alla possibilit� di trasformare\nle offese in qualcosa di costruttivo per lui.\nGiunto nella sua camera cerc� di internet ogni informazione su Buddha,\ne pi� leggeva pi� capiva che difronte a lui si era prospettata una prova\ndi coraggio, completamente diversa da quelle che aveva affrontato in passato,\ndove muscoli, forza fisica, oblio della mente, non erano pi� le sue armi\nper affrontare la vita .\nUn cerchio luminoso lo chiamava a intraprendere un inerpicato sentiero\nche passava vicino a piccoli specchi d acqua, in ognuno di essi Diego vedeva\nla sua immagine riflessa sempre pi� nitida, i suoi occhi di laghetto in laghetto\nsprizzavano sempre pi� gioia, il sudore che colava a terra faceva nascere fiori\ndove passava, le ferite della sua vita cantavano canzoni d amore.\nEppure era il sentiero pi� faticoso e difficile che avesse mai visto,\nogni cosa o essere che incontrava gli suggerivano di trasformare i suoi pensieri\nbrutti in occasioni, non era per nulla semplice pensava Diego,\neppure continu� il suo viaggio. Il suo spirito divenne forte come la roccia,\ne il suo cuore rosso blu, divent� esempio per i suoi amici!"}]}]},dir:g,path:"\u002FarticlesMDMA\u002FAnnaG-Diego",extension:h,createdAt:w,updatedAt:"2021-07-05T16:34:39.674Z"},{slug:"Francesca-Diego",tema:e,titolo:H,autore:G,parole:e,data:r,tags:e,img:p,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Aveva proprio centrato il bersaglio nonostante fosse lontano, all'orizzonte..\nMa lui quando mirava, restava immobile, imperturbabile, preciso, e ogni volta la sua azione era\nperfetta. Aveva la pazienza di un Buddha! Restava nella stessa postazione per giorni .. fino a\nquello che lui considerava il giusto momento per scoccare la freccia dal suo arco zen.\nQuel giorno la luce del Sole era cosi' nitida e scintillante che ogni cosa su cui i suoi occhi si\nposavano, ne rifrangevano il puro riflesso cristallino.\nL'ariete era la' sopravvento, la sua possente silhouette disegnata dal sole alle spalle; l'istinto\nl'aveva condotto su quelle rocce lontane dalla sua comunita', doveva dare prova di coraggio e\nsalvare la sua stirpe. Era lui che cercavano! Volevano il suo vello pregiato, lungo color del miele e\nmorbido come la seta.\nPer un attimo il suo sguardo luminoso incrocio' quello del cacciatore, che era appostato lungo il\nsentiero dietro la roccia piu' alta. L'uomo si senti' all'improvviso piccolo e spoglio al suo cospetto,\ne come ogni volta compi' l'azione giusta.. quella fu l'ultima freccia che il suo arco scaglio contro\nuna creatura."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancesca-Diego",extension:h,createdAt:"2021-07-05T16:36:50.782Z",updatedAt:i},{slug:"FrancescoP-Esistenza-1",tema:e,titolo:"Esistenza",autore:j,parole:"presenza, calze, paranormale, bigbang, gratitudine, sottile,  ricchezza, resistenza, proteggere, tremula, fragile, respiro",data:I,tags:e,img:"mdma2.jpg",toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Signore e Signori, vi ringrazio della vostra presenza.\nL'incontro di oggi, come saprete, sara' dedicato allo studio dell'uso del colore delle calze nell'opera del Fintoretto.\nSebbene il rapporto del Fintoretto con le calze nel paranormale sia gia' stato enucleato nell'opera di Giacomo Deridi,\nnoi preferiamo un'analisi novella, in un certo qual modo risalendo al bigbang dell'universo creativo dell'artista in questione,\nrinnovando l'ovvia gratitudine dovuta al maestro Mario Triste, che e' stato forse il piu' sottile ed analitico\ncritico della ricchezza di riferimenti nelle calze nell'opera del nostro, e che con maniacale resistenza ha saputo\nmantenere, direi quasi proteggere con affetto, la tremula voce esistenziale del nostro fragile ma deciso artista.\nUna posizione che il maestro ha saputo mantenere fino all'ultimo respiro.\nGrazie."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Esistenza-1",extension:h,createdAt:J,updatedAt:i},{slug:"Roberto-FrancescoP",tema:e,titolo:"Francesco Porta",autore:K,parole:e,data:r,tags:e,img:p,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Quel bastain contrario eternamente barbutoe fantasioso di mago Merlino\ninventore geniale si mise seduto in poltrona a mangiare la sua insalata\naccanto a lui il suo cane che lui chiamava amatamente gattaro."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FRoberto-FrancescoP",extension:h,createdAt:w,updatedAt:i},{slug:"Elisa-Fuggire_dal_mondo-1",tema:o,titolo:o,autore:l,parole:e,data:m,img:L,tags:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Sono il più giovane del mio battaglione, ho solo 15 anni, ma tutti devono combattere per difendere la patria, nessuno escluso, ragazzi, uomini, talvolta bambini."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Solo le donne sono potute rimanere a casa, lavorando nelle fabbriche al posto degli uomini e continuando a mantenere la casa."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Sospirò con aria assonnata, andando a rigirarmi nel pagliericcio che sto usando come letto, andando a volgere lo sguardo al cielo stellato."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"La trincea é silenziosa, nessun rumore, nessuno sparo, solo qualche lamento dei soldati provenienti dall'infermeria del campo."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Approfitto subito di quel silenzioso per evadere, iniziando a viaggiare con la fantasia, lasciandomi trascinare dalla mia capacità di immedesimarsi in storie che io stesso mi invento."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Osservò il cielo, immaginandomi di essere un pescatore di stelle che, attirato dal ruggito della costellazione del leone, decido di gettare la mia esca nel blu del cielo notturno."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Riesco a immaginarmi su quella barca, una barca bianca e luminosa, che deve confondersi con il cielo per non attirare l'attenzione degli uomini sulla terra, riesco a immaginarmi mentre mi abbandono al silenzio e alla calma della notte, osservando il piccolo cubo di energia che sto usando come esca galleggiare nell'acqua, mentre aspetto che la costellazione che ho scelto di catturare quella notte abbocchi."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Magari lo farà, magari abboccherà e tornerò sul mio pianeta decisamente soddisfatto...o magari no, magari non lo farà e tornerò a mani vuote, d'altronde un leone é difficile da catturare."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Sospiro, sentendo a un tratto la lenza tirare, ecco! Ha abboccato, ora non mi resta che girare il mulinetto e-."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"\"Presto! Alle armi!\""}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"E no, non saprò mai se sarei riuscito a catturare il leone."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Velocemente mi alzo dal pagliericcio, lasciando che quell'avventura sia interrotta dalla chiamata alle armi del mio sergente."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Ho appena imboccato la mia postazione, dietro i sacchi di sabbia, riesco a malapena a ricaricare il fucile che sento l'esplosione che riapre il fuoco tra le trincee."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FElisa-Fuggire_dal_mondo-1",extension:h,createdAt:E,updatedAt:i},{slug:"Elisa-Fuggire_dal_mondo-2",tema:o,titolo:o,autore:l,parole:e,data:m,img:L,tags:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Non ne ho più voglia di stare ad ascoltare questa stupida lezione di matematica…"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Alice sospirò, andando ad appoggiare la biro sul quaderno pieno di numeri e formule."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Non ce la faceva più, era da due ore che il prof andava avanti a spiegare senza nemmeno fermarsi un attimo e il suo cervello stava iniziando a fumare."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Si sistemò una ciocca di capelli biondi dietro all'orecchio, andando a guardare che cosa stava facendo Jack, il suo compagno di banco"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"A) Che fai?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Chiese Alice, ma Jack, tutto preso a scarabocchiare qualcosa sul quaderno non le diede attenzione."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Alice si ritrovò di nuovo a sospirare, andando ad appoggiare la testa contro il banco"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"A) Non sarebbe bello poter fuggire da qui? Da questa stupida classe?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Pensava che Jack non le avrebbe risposto, come poco prima, ma questa volta lo fece, mostrandogli un quaderno pieno di disegni"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"J) Si può fare invece, si può fuggire, lo vedi?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"A quelle parole la ragazza iniziò a sfogliare tutti i disegni che il suo compagno aveva fatto e capendo solo ora che aveva raccontato una storia, la loro storia"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"J) possiamo rubare il tappeto volante ad Aladino, saltarci in cima e volare dove vogliamo, che sia in Perù, a Parigi o a Tokyo, oppure se preferisci possiamo attraversare una porta magica e aiutare Ali Babà a sconfiggere i 40 ladroni e sai qual'é la cosa bella?"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"A) quale? "},{type:b,tag:u,props:{},children:[{type:a,value:"Chiese Alice?"}]}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"J) Che possiamo tornare indietro quando vogliamo, o qui ad ascoltare questa noiosa lezione di matematica oppure andare ancora più indietro fino a dove siamo nati e non dobbiamo nemmeno portarci una valigia perché continueremo a essere qui, in questo presente, in questa realtà, almeno con il nostro corpo."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Con la mente invece saremo da tutt'altra parte, in un altro universo!"}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Alice lo guardò meravigliata da tutte quelle parole."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Loro due che viaggiavano insieme per mondi sconosciuti, vivendo mille avventure, sarebbe stato bellissimo, sicuramente più bello che ascoltare questa stupida lezione sull'arrotondamento esponenziale."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FElisa-Fuggire_dal_mondo-2",extension:h,createdAt:M,updatedAt:i},{slug:"FrancescoP-Fuggire_dal_mondo-1",tema:o,titolo:o,autore:j,parole:"tappeto volante, porta magica, ali baba', tornare indietro, dove siamo nati, valigia, presente, universo, arrotondamento esponenziale",data:"17 febbraio 2021",tags:e,img:n,video:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Il commissario CANDEGGINA dopo l'avventura del TAPPETO VOLANTE ..."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Ah no, scusate quella e' un'altra storia."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Il TAPPETO VOLANTE veleggiava tranquillo seguendo una rotta assai incerta.\nSeguiva le correnti d'aria facendosi trasportare per un po' per poi cadere in picchiata verso il mare\ne quindi d'improvviso risalire."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"La PORTA MAGICA che si apre sul mondo dei sogni spesso mi conduce a questo sogno (di essere un tappeto volante).\nQualche volta invece mi conduce a pessimi sogni dove sono uno dei quaranta ladroni di ALI BABA'. In questo sogno\nrubo attimi di vita e a volte anche lunghi periodi di vita. Della mia s'intende. Ma dopotutto non sono tutte le vite legate tra\nloro? Quindi rubo la vita all'universo? Forse si.\nCerto e' un sogno non piacevole.\nMa non si puo' TORNARE INDIETRO, tornare a DOVE SIAMO NATI.\nNon si puo'? Davvero non si puo' tornare indietro?\nE dove siamo nati non e' lo stesso luogo in cui andremo quando moriremo?\nSe si, allora si puo' tornare indietro.\nMa ci tocca fare questo viaggio di vita, ci tocca aspettare un po' prima del ritorno.\nSperando che il viaggio sia come le ferrovie, si arriva certo ma sempre in ritardo ...\nIn ogni caso e' bene avere la VALIGIA pronta. Non si sa mai.\nMa quindi passato, PRESENTE e futuro esistono solo durante questo viaggio ...\nE questo viaggio e' un sogno?\nE il sogno e' il mio sogno?\nE quindi se rubo la vita all'UNIVERSO rubo la vita degli altri e quindi la mia e quindi\nil luogo dove sono nato che e' lo stesso del mio ritorno sempre con la stessa valigia\nmi riporta ad essere un ladro, uno dei quaranta ladroni di Ali' Baba'?\nE se dovessi poi riuscire ad uscire dalla porta magica magari in virtu' di\nun'ARROTONDAMENTO ESPONENZIALE di sogni e pensieri, potrei magari tornare ad essere tappeto volante\ne librarmi libero nell'aria?\nE se il tappeto volante infila la porta magica di Ali' Baba' senza tornare indietro a dove siamo nati senza valigia in un presente\ndi questo universo?\nL'arrotondamento esponenziale puo' disporre l'universo presente a prepararci la valigia e da dove siamo nati farci tornare\nindietro a quando con Ali' Baba' si passava la porta magica su di un tappeto volante?\nE ..."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Fuggire_dal_mondo-1",extension:h,createdAt:J,updatedAt:i},{slug:"FrancescoP-Fuggire_dal_mondo-2",tema:o,titolo:o,autore:j,parole:"mongolfiera, pietra, per un istante, zavorra, serenita', aquilone, asino volante, purificazione, viscoso",data:"10 marzo 2021",tags:e,img:n,video:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Se la mia testa fosse una MONGOLFIERA si eleverebbe, trascinandosi dietro il resto del corpo, o almeno\nlo spererei. Ed invece e' solida come una PIETRA scolpita in caratteri cuneiformi. E' un labirinto di pensieri\nperlopiu' incomprensibili a me stesso. Ma se PER UN ISTANTE potessi cancellare la pietra della mia testa?\nSe fossero proprio quelle scritte la ZAVORRA del mio pensiero, le responsabili di quella disturbante mancanza\ndi SERENITA'?\nLa serenita' e' un AQUILONE?\nMa le parole incise sulla mia pietra sono troppo antiche per poterle cancellare.\nUna vecchia, molto tempo fa, mi disse di poterle leggere e che significavano ASINO VOLANTE. Ma che significa poi?\nLa vita come percorso di PURIFICAZIONE quasi un compito da svolgere?\nPurificazione dei pensieri, cancellare la propria pietra, forse distruggerla fino a farla diventare sabbia,\ned avere infine una testa MONGOLFIERA?\nTutto questo e' troppo VISCOSO per la mia piccola pietra incisa in caratteri cuneiformi.\nPreferisco non sapere."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Fuggire_dal_mondo-2",extension:h,createdAt:N,updatedAt:i},{slug:"Roberto-Marina",tema:e,titolo:"Marina",autore:K,parole:e,data:r,tags:e,img:p,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"La leonessa al calar della sera guardandosi allo specchio disse gioiosa\ndomani andr� dall'estetista poi uscita dall'estetista andr� a mettere a posto\nquei pochi riccioli che mi sono rimasti ed uscendo dal parrucchiere\nun uragano all'improvviso mi rovin� la mia acconciatura cos� con un sorriso\nspumeggiante andai a comprarmi un tacco dodici. Uscendo dal negoziante\nl'uragano si trasform� in una pioggia intima di carinzia."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FRoberto-Marina",extension:h,createdAt:w,updatedAt:i},{slug:"FrancescoP-Percorso-1",tema:e,titolo:"Percorso",autore:j,parole:"usato, cintura, castita', vario, sulla strada, in discesa, donna, morire, volo",data:s,tags:e,img:O,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Vendo uomo vintage. Usato poco. In discrete condizioni generali. Regalo anche una cintura taglia large per lo stesso.\nSebbene non abbia vissuto in totale castita' ha pochi malfunzionamenti. Qualche vario graffio sulla pelle.\nTrovato molti anni fa sulla strada. Sembra sia stato abbandonato dopo essere caduto da una auto che procedeva\nin discesa, quasi certamente guidata da una donna. Sono costretta a venderlo perche' mi fa morire dalla noia e,\nora, io vorrei prendere il volo da questa vita. Chiamare il ..."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Percorso-1",extension:h,createdAt:N,updatedAt:i},{slug:"FrancescoP-Ramo-1",tema:e,titolo:"Ramo",autore:j,parole:"uccellini, boato, cerchio, frescura, serena, capanna, unghie laccate, colpito, salvezza",data:s,tags:e,img:O,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Uccelli ed uccellini fanno sempre un gran boato.\nCinguettii colorati o urla estatiche di femmine in cerchio.\nNon e' proprio di frescura che si parla, ma del feroce desiderio a breve consumato\nnella quiete serena della capanna nel bosco.\nL'uomo dalle unghie laccate e' rimasto colpito da questo rituale.\nE' quasi impaurito dalla enorme forza primordiale di quell'atto.\nEgli, che non credeva piu' nella salvezza, ora sa che anch'essa era impaurita."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Ramo-1",extension:h,createdAt:P,updatedAt:i},{slug:"Elisa-Su_un_amaca_in_messico-1",tema:Q,titolo:Q,autore:l,parole:"all'arrivo, dondolando, desiderio immenso, mezcal, finestra, come un cane sciolto, gioia, riposo",data:m,img:"by-the-sea.jpg",tags:e,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"All'arrivo a Tulum non sapevo dove o come girarmi, non sapevo un accidenti di spagnolo, non avevo persone o amici a cui chiedere e l'appartamento che avevo affittato altro non era che una bettola da 100 pesos al mese con vicini urlanti, topi che mordicchiavano qualunque cosa trovassero e l'acqua della doccia costantemente fredda."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Era passato appena un mese quando avevo preso il biglietto per tornarmene nella mia cara e affollata New York, quando incontrai un ragazzo, Hector che mi fece vedere Tulum e il Messico con occhi differenti convincendomi a rimanere."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Non posso credere ora, che sono passati quattro anni e che, strimpellando le corde della mia chitarra, mi sto dondolando sull'Altalena che pende dal soffitto bianco della mia casa, con un desiderio immenso di vedere calare la sera per uscire tutta truccata e vestita per le strade di Tulum a festeggiare il Dia de Los muertos, il giorno in cui i morti tornano nella terra dei vivi e fare a gara con i miei amici a chi manda giù più shot di mescal con tanto di cappello a chi trova il coraggio di mangiare il bruco all'interno della bottiglia."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"È questo che penso, ora, mentre fisso fuori dalla finestra il sole torrido, che illumina la città rendendola arida ma piena di vita, proprio come me, che so già che stasera, come in cane sciolto io andrò in giro per locali, suonando con i Mariachi, ridendo e ballando, piena di vita e magari... ubriaca."}]},{type:a,value:d},{type:b,tag:c,props:{},children:[{type:a,value:"Non so, è assurdo, assurdo pensare che quattro anni fa, se non avessi incontrato Hector, con cui adesso sono sposata, avrei rinunciato a tutta questa gioia, trovando magari riposo in un noioso e grigio grattacielo newyorkese."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FElisa-Su_un_amaca_in_messico-1",extension:h,createdAt:M,updatedAt:i},{slug:"FrancescoP-Verita-1",tema:e,titolo:"Verita'",autore:j,parole:"nascosta, legno, scontata, ferita, relativa, cristallo, a volte fa male, coraggio, maturità, impossibile, imbrigliata, ciò che è",data:I,tags:e,img:p,toc:[],body:{type:f,children:[{type:b,tag:c,props:{},children:[{type:a,value:"Giorgio e Alice siedono ad un tavolo.\nI loro visi esprimono tensione.\nE' Alice che inizia a parlare.\n\"perche' me l'hai nascosta?\", dice con voce flebile.\nGiorgio, tamburellando nervosamente sul tavolo di legno, ritiene che la risposta sia scontata. E tace.\nE' Alice che prosegue.\n\"mi hai ferita.\" dice con relativa calma. Ma si intuisce la sua inqiuetudine.\nE prosegue.\n\"mi ci vorrebbe una sfera di cristallo per capire cosa pensi!\nA volte fa male il tuo silenzio.\"\nAlice si infervora e prosegue tutto d'un fiato:\n\"Vorrei che tu avessi piu' coraggio che almeno per una volta ti comportassi da uomo,\nche dimostrassi la tua maturita' ... ma forse e' impossibile.\"\nOrmai Alice e' stanca ... e con voce bassa prosegue.\n\"mi sento imbrigliata in tutto questo.\"\nE conclude.\n\"con te\".\nE Giorgio tace.\nEppure il suo sguardo e' puro d'amore.\nPuro amore per Alice.\nPoi quasi d'improvviso si alza e bacia Alice.\nLei ricambia il bacio.\nGiorgio prende carta e penna e deciso scrive qualcosa che passa ad Alice.\nAlice legge sottovoce.\n\"non posso farci nulla, io sono muto. Questo e' cio' che e'.\"\nE finalmente Alice capisce: questo e' amore."}]}]},dir:g,path:"\u002FarticlesMDMA\u002FFrancescoP-Verita-1",extension:h,createdAt:P,updatedAt:i}]}],fetch:{},mutations:void 0}}("text","element","p","\n",null,"root","\u002FarticlesMDMA",".md","2021-07-04T07:35:56.881Z","Francesco P","Assuefazione","Elisa","maggio 2021","mdma1.jpg","Fuggire dal mondo","207666.jpg","Boomerang","giugno 2021","30 dicembre 2020","pexels-pixabay-2163.jpg","em","2021-07-05T16:36:50.738Z","2021-07-05T16:36:50.734Z","2021-07-05T16:36:50.754Z","serie 3","hifi-texture-adventures.jpg","serie 4","2021-07-05T16:36:50.758Z","2021-07-05T16:36:50.762Z","2021-07-05T16:36:50.742Z","2021-07-05T16:36:50.746Z","2021-07-05T16:36:50.766Z","Francesca","Diego","23 dicembre 2020","2021-07-05T16:36:50.770Z","Roberto","pexels-miguel.jpg","2021-07-05T16:36:50.750Z","2021-07-05T16:36:50.774Z","207655.jpg","2021-07-05T16:36:50.778Z","Su un'amaca in Messico")));